import React, { createContext, useState, ReactNode } from 'react';
import { PortfolioItemType } from '../types/portfolio';
import { portfolioData } from '../utils/constants';

interface PortfolioContextType {
  portfolioItems: PortfolioItemType[];
}

export const PortfolioContext = createContext<PortfolioContextType>({
  portfolioItems: [],
});

export const PortfolioProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [portfolioItems] = useState<PortfolioItemType[]>(portfolioData);

  return (
    <PortfolioContext.Provider value={{ portfolioItems }}>
      {children}
    </PortfolioContext.Provider>
  );
};

